  "inlineSchema": "// Prisma Schema for VoteVideo\n// 数据库：SQLite\n// 生成时间：2026-06-11\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// --- 用户表 ---\nmodel User {\n  uid               Int      @id @default(autoincrement())\n  username          String   @unique\n  password          String\n  profilePictureUrl String?\n  info              String?\n  followerCount     Int      @default(0)\n  followingCount    Int      @default(0)\n  createdAt         DateTime @default(now())\n\n  // 关联关系\n  videos        Video[] // 用户上传的视频\n  essays        Essay[] // 用户上传的文章\n  posts         Post[] // 用户发布的动态\n  comments      Comment[] // 用户发布的评论\n  sentMessages  Message[]       @relation(\"SentMessages\") // 发送的消息\n  dialogues1    Dialogue[]      @relation(\"DialogueParticipant1\") // 作为参与者1的对话\n  dialogues2    Dialogue[]      @relation(\"DialogueParticipant2\") // 作为参与者2的对话\n  notifications Notification[] // 发送的通知\n  favourites    UserFavourite[] // 收藏\n  history       UserHistory[] // 历史记录\n  following     UserFollowing[] @relation(\"Following\") // 关注的人\n  followers     UserFollowing[] @relation(\"Follower\") // 粉丝\n}\n\n// --- 视频表 ---\nmodel Video {\n  vid            Int      @id @default(autoincrement())\n  title          String\n  coverUrl       String?\n  videoUrl       String?\n  duration       String?\n  viewCount      Int      @default(0)\n  messageCount   Int      @default(0)\n  likeCount      Int      @default(0)\n  favouriteCount Int      @default(0)\n  createdAt      DateTime @default(now())\n\n  // 关联关系\n  uploader_uid Int\n  uploader     User       @relation(fields: [uploader_uid], references: [uid])\n  comments     Comment[]\n  videoTags    VideoTag[]\n}\n\n// --- 文章表 ---\nmodel Essay {\n  eid            Int      @id @default(autoincrement())\n  title          String\n  text           String\n  viewCount      Int      @default(0)\n  commentCount   Int      @default(0)\n  likeCount      Int      @default(0)\n  favouriteCount Int      @default(0)\n  createdAt      DateTime @default(now())\n\n  // 关联关系\n  uploader_uid Int\n  uploader     User      @relation(fields: [uploader_uid], references: [uid])\n  comments     Comment[]\n}\n\n// --- 动态表 ---\nmodel Post {\n  pid          Int      @id @default(autoincrement())\n  text         String?\n  pictureList  String? // JSON 字符串\n  videoList    String? // JSON 字符串\n  viewCount    Int      @default(0)\n  commentCount Int      @default(0)\n  likeCount    Int      @default(0)\n  createdAt    DateTime @default(now())\n\n  // 关联关系\n  uploader_uid Int\n  uploader     User      @relation(fields: [uploader_uid], references: [uid])\n  comments     Comment[]\n}\n\n// --- 标签表 ---\nmodel Tag {\n  tid            Int    @id @default(autoincrement())\n  tagName        String @unique\n  likeCount      Int    @default(0)\n  favouriteCount Int    @default(0)\n  commentCount   Int    @default(0)\n\n  // 关联关系\n  videoTags VideoTag[]\n}\n\n// --- 视频-标签中间表 ---\nmodel VideoTag {\n  vid   Int\n  tid   Int\n  video Video @relation(fields: [vid], references: [vid])\n  tag   Tag   @relation(fields: [tid], references: [tid])\n\n  @@id([vid, tid])\n}\n\n// --- 评论表 ---\nmodel Comment {\n  cid             Int      @id @default(autoincrement())\n  text            String\n  type            String   @default(\"text\") // 'text' 或 'picture'\n  pictureList     String? // JSON 字符串\n  viewCount       Int      @default(0)\n  likeCount       Int      @default(0)\n  favouriteCount  Int      @default(0)\n  subCommentCount Int      @default(0)\n  createdAt       DateTime @default(now())\n\n  // 关联关系\n  vid           Int?\n  video         Video?    @relation(fields: [vid], references: [vid])\n  uploader_uid  Int\n  uploader      User      @relation(fields: [uploader_uid], references: [uid])\n  replyTo_cid   Int?\n  replies       Comment[] @relation(\"CommentReplies\")\n  parentComment Comment?  @relation(\"CommentReplies\", fields: [replyTo_cid], references: [cid])\n  essay         Essay?    @relation(fields: [vid], references: [eid])\n  post          Post?     @relation(fields: [vid], references: [pid])\n}\n\n// --- 用户收藏中间表 ---\nmodel UserFavourite {\n  uid     Int\n  type    String // 'video', 'essay', 'post'\n  item_id Int\n  addDate DateTime @default(now())\n  user    User     @relation(fields: [uid], references: [uid])\n\n  @@id([uid, type, item_id])\n}\n\n// --- 用户历史中间表 ---\nmodel UserHistory {\n  uid     Int\n  type    String // 'video', 'essay', 'post'\n  item_id Int\n  addDate DateTime @default(now())\n  user    User     @relation(fields: [uid], references: [uid])\n\n  @@id([uid, type, item_id])\n}\n\n// --- 用户关注中间表 ---\nmodel UserFollowing {\n  uid           Int\n  following_uid Int\n  user          User @relation(\"Following\", fields: [uid], references: [uid])\n  following     User @relation(\"Follower\", fields: [following_uid], references: [uid])\n\n  @@id([uid, following_uid])\n}\n\n// --- 对话表 ---\nmodel Dialogue {\n  mid              Int       @id @default(autoincrement())\n  participant1_uid Int\n  participant2_uid Int\n  lastMessage      String?\n  lastDate         DateTime?\n\n  // 关联关系\n  participant1 User      @relation(\"DialogueParticipant1\", fields: [participant1_uid], references: [uid])\n  participant2 User      @relation(\"DialogueParticipant2\", fields: [participant2_uid], references: [uid])\n  messages     Message[]\n}\n\n// --- 消息表 ---\nmodel Message {\n  id         Int      @id @default(autoincrement())\n  mid        Int\n  sender_uid Int\n  text       String\n  createdAt  DateTime @default(now())\n\n  // 关联关系\n  dialogue Dialogue @relation(fields: [mid], references: [mid])\n  sender   User     @relation(\"SentMessages\", fields: [sender_uid], references: [uid])\n}\n\n// --- 通知表 ---\nmodel Notification {\n  nid        Int      @id @default(autoincrement())\n  type       String // 'like', 'comment', 'follow', 'favourite', 'at'\n  from_uid   Int\n  targetType String // 'video', 'essay', 'post', 'comment'\n  targetId   Int\n  parentType String? // 可选\n  parentId   Int?\n  text       String\n  isRead     Boolean  @default(false)\n  createdAt  DateTime @default(now())\n\n  // 关联关系\n  fromUser User @relation(fields: [from_uid], references: [uid])\n}\n",
